            if (code.includes('DriverManager.getConnection')) {
                return 'This Java code uses JDBC to connect to the MySQL server (no default database), then creates a Statement and executes the DDL statement with <code>executeUpdate()</code>.';
            }
            if (code.includes('mysql.connector.connect')) {
                return 'This Python code uses the MySQL Connector to connect without a default database, then creates a cursor and executes the <code>CREATE DATABASE</code> statement.';
            }
            return 'This is a MySQL snippet related to creating a database. Click the AI icon for a detailed explanation.';
