        <pre><code>import mysql.connector
from mysql.connector import Error
try:
    conn = mysql.connector.connect(
        host='localhost',
        user='root',
        password='password'
    )
    cursor = conn.cursor()
    sql = "CREATE USER 'Sarika'@'localhost' IDENTIFIED BY 'password' ACCOUNT LOCK"
    cursor.execute(sql)
    print('User locked.')
except Error as e:
    print(f'Error: {e}')
finally:
    if conn.is_connected():
        cursor.close()
        conn.close()</code></pre>
