        <pre><code>import mysql.connector
from mysql.connector import Error
try:
    conn = mysql.connector.connect(
        host='localhost',
        user='root',
        password='password',
        database='TUTORIALS'
    )
    cursor = conn.cursor()
    sql = 'DROP TRIGGER testTrigger'
    cursor.execute(sql)
    print('Trigger dropped.')
except Error as e:
    print(f'Error: {e}')
finally:
    if conn.is_connected():
        cursor.close()
        conn.close()</code></pre>
