    sql = "CREATE TRIGGER before_update_trigger BEFORE UPDATE ON USERS FOR EACH ROW BEGIN IF NEW.AGE < 0 THEN SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Age Cannot be Negative'; END IF; END"
