                var explanation = generateExplanation(code);
                explanationDiv.innerHTML = '<p><strong>Code snippet:</strong></p><pre><code>' + code + '</code></pre><p><strong>Explanation:</strong><br>' + explanation + '</p>';
                modal.style.display = 'flex';
